# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

import os
from flask import Flask, request, jsonify
from web3 import Web3
from eth_account.messages import encode_defunct
import secrets
import time
from datetime import datetime, timedelta
import jwt

app = Flask(__name__)

# Configuration
SECRET_KEY = os.environ.get('SECRET_KEY', secrets.token_hex(32))
JWT_EXPIRATION_HOURS = 24

# In-memory storage for nonces (use Redis/database in production)
nonces = {}

# Web3 instance (can connect to Infura, Alchemy, or local node)
w3 = Web3(Web3.HTTPProvider(os.environ.get('WEB3_PROVIDER_URI', 'https://mainnet.infura.io/v3/YOUR_INFURA_KEY')))


def generate_nonce():
    """Generate a random nonce for signature verification"""
    return secrets.token_hex(16)


def create_auth_message(address, nonce):
    """Create a standardized authentication message"""
    return f"Sign this message to authenticate with your wallet.\n\nAddress: {address}\nNonce: {nonce}\nTimestamp: {int(time.time())}"


def verify_signature(message, signature, expected_address):
    """Verify an Ethereum signature and return True if valid"""
    try:
        # Encode the message
        message_hash = encode_defunct(text=message)
        
        # Recover the address from the signature
        recovered_address = w3.eth.account.recover_message(message_hash, signature=signature)
        
        # Compare addresses (case-insensitive)
        return recovered_address.lower() == expected_address.lower()
    except Exception as e:
        print(f"Signature verification error: {e}")
        return False


def create_jwt_token(address):
    """Create a JWT token for authenticated user"""
    payload = {
        'address': address.lower(),
        'exp': datetime.utcnow() + timedelta(hours=JWT_EXPIRATION_HOURS),
        'iat': datetime.utcnow()
    }
    return jwt.encode(payload, SECRET_KEY, algorithm='HS256')


def verify_jwt_token(token):
    """Verify and decode JWT token"""
    try:
        payload = jwt.decode(token, SECRET_KEY, algorithms=['HS256'])
        return payload
    except jwt.ExpiredSignatureError:
        return None
    except jwt.InvalidTokenError:
        return None


@app.route('/api/auth/nonce', methods=['POST'])
def get_nonce():
    """Generate and return a nonce for a given address"""
    data = request.get_json()
    
    if not data or 'address' not in data:
        return jsonify({'error': 'Address is required'}), 400
    
    address = data['address']
    
    # Validate Ethereum address format
    if not Web3.is_address(address):
        return jsonify({'error': 'Invalid Ethereum address'}), 400
    
    # Normalize address to checksum format
    address = Web3.to_checksum_address(address)
    
    # Generate nonce
    nonce = generate_nonce()
    
    # Store nonce with timestamp (expire after 5 minutes)
    nonces[address.lower()] = {
        'nonce': nonce,
        'timestamp': time.time(),
        'expires_at': time.time() + 300  # 5 minutes
    }
    
    # Create the message to be signed
    message = create_auth_message(address, nonce)
    
    return jsonify({
        'address': address,
        'nonce': nonce,
        'message': message
    }), 200


@app.route('/api/auth/verify', methods=['POST'])
def verify_and_authenticate():
    """Verify signature and issue JWT token"""
    data = request.get_json()
    
    if not data or 'address' not in data or 'signature' not in data or 'message' not in data:
        return jsonify({'error': 'Address, signature, and message are required'}), 400
    
    address = data['address']
    signature = data['signature']
    message = data['message']
    
    # Validate Ethereum address
    if not Web3.is_address(address):
        return jsonify({'error': 'Invalid Ethereum address'}), 400
    
    address_lower = address.lower()
    
    # Check if nonce exists
    if address_lower not in nonces:
        return jsonify({'error': 'No nonce found for this address. Please request a nonce first.'}), 400
    
    nonce_data = nonces[address_lower]
    
    # Check if nonce has expired
    if time.time() > nonce_data['expires_at']:
        del nonces[address_lower]
        return jsonify({'error': 'Nonce has expired. Please request a new nonce.'}), 400
    
    # Verify the signature
    is_valid = verify_signature(message, signature, address)
    
    if not is_valid:
        return jsonify({'error': 'Invalid signature'}), 401
    
    # Verify the message contains the correct nonce
    if nonce_data['nonce'] not in message:
        return jsonify({'error': 'Invalid nonce in message'}), 401
    
    # Delete used nonce
    del nonces[address_lower]
    
    # Create JWT token
    token = create_jwt_token(address)
    
    return jsonify({
        'success': True,
        'token': token,
        'address': Web3.to_checksum_address(address),
        'expiresIn': JWT_EXPIRATION_HOURS * 3600
    }), 200


@app.route('/api/auth/validate', methods=['GET'])
def validate_token():
    """Validate JWT token from Authorization header"""
    auth_header = request.headers.get('Authorization')
    
    if not auth_header:
        return jsonify({'error': 'Authorization header is required'}), 401
    
    try:
        # Extract token from "Bearer <token>"
        token = auth_header.split(' ')[1] if ' ' in auth_header else auth_header
    except IndexError:
        return jsonify({'error': 'Invalid authorization header format'}), 401
    
    payload = verify_jwt_token(token)
    
    if not payload:
        return jsonify({'error': 'Invalid or expired token'}), 401
    
    return jsonify({
        'valid': True,
        'address': payload['address'],
        'expiresAt': payload['exp']
    }), 200


@app.route('/api/protected', methods=['GET'])
def protected_route():
    """Example protected route that requires authentication"""
    auth_header = request.headers.get('Authorization')
    
    if not auth_header:
        return jsonify({'error': 'Authorization required'}), 401
    
    try:
        token = auth_header.split(' ')[1] if ' ' in auth_header else auth_header
    except IndexError:
        return jsonify({'error': 'Invalid authorization header'}), 401
    
    payload = verify_jwt_token(token)
    
    if not payload:
        return jsonify({'error': 'Invalid or expired token'}), 401
    
    return jsonify({
        'message': 'Access granted to protected resource',
        'address': payload['address'],
        'data': 'This is protected data only accessible to authenticated users'
    }), 200


@app.route('/api/health', methods=['GET'])
def health_check():
    """Health check endpoint"""
    return jsonify({
        'status': 'healthy',
        'web3_connected': w3.is_connected(),
        'timestamp': int(time.time())
    }), 200


# Cleanup expired nonces periodically
def cleanup_expired_nonces():
    """Remove expired nonces from storage"""
    current_time = time.time()
    expired_addresses = [
        addr for addr, data in nonces.items()
        if current_time > data['expires_at']
    ]
    for addr in expired_addresses:
        del nonces[addr]


# Middleware to clean up expired nonces before each request
@app.before_request
def before_request():
    cleanup_expired_nonces()


if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=True)